var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nSCN No. TPM001M000139-05: <color=#ffd34c>강소영</color>","JPN":"NETBLINK SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION：<color=#ffd34c>CONFIRMED</color>\\nSCN No. TPM001M000139-05：<color=#ffd34c>マエカワ・ナツミ</color>","ENG":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nSCN No. TPM001M000139-05: <color=#ffd34c>Kang Soyoung</color>","TWN":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No.TPM001M000139-05: <color=#ffd34c>姜素英</color>"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"음...... 우리 서에서 가장 특이한 사람이요?","JPN":"ふむ……うちの署で一番個性的な人ですか？","ENG":"Hmm... The most unusual character in our station?","TWN":"呃……我們署裡最特別的人嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그럼 역시 강소영 경위님 아닐까요?","JPN":"たぶん、マエカワ・ナツミ警部補だと思います。","ENG":"I'd have to say it's Lieutenant Kang Soyoung.","TWN":"那應該是姜素英警衛吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그 왜 유배지...... 아, 아니 제 4 특별기동수사대에 2년째 혼자 계시는 그 분이요.","JPN":"えっと、その……左遷先……あ、いや、第4特別機動捜査隊に1人で2年も勤めてる方ですよ。","ENG":"You know, the one who's been exiled... uh, I mean, assigned to Police SWAT 4 all by herself for the past two years.","TWN":"獨自在流放地……啊，我是說獨自在第四特遣機動隊待了兩年的那位。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아는 사람만 아는 이야기이긴 한데, 보기와는 다르게 엄청 유능한 분이에요.","JPN":"知る人ぞ知る話なんですけど、見かけによらずすごく有能なんです。","ENG":"Not everyone knows this, but she's actually a lot more capable than she looks.","TWN":"雖然沒什麼人知道，但外表不一樣，她是個很有能力的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"지난 번 미제사건도 사실 강소영 경위님이 힌트를 줘서 해결한 거거든요?","JPN":"この間の未解決事件も、実はマエカワ警部補のヒントのおかげで解決しました。","ENG":"We recently solved a cold case thanks to her tips.","TWN":"上次未結案的事件，也是多虧姜警衛給了提示，我們才能解決的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"진급이 빠르거나 표창을 받거나 하진 못했지만 수사에 대한 감이 엄청 뛰어나세요.","JPN":"昇級が早いわけでも、表彰されるわけでもありませんが、捜査への勘がとても鋭いんです。","ENG":"She might not have had much luck with promotions or awards, but she sure does have an extraordinary gut instinct when it comes to solving cases.","TWN":"雖然沒有升遷或者被表彰過，不過姜警衛在調查中的直覺非常準。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"수사란 게 말이 쉽지, 달랑 사건파일 하나 들고 뛰어다니는 게 보통 일이 아니거든요.","JPN":"捜査と言えば聞こえはいいかもしれませんが、頼れるものが事件ファイルだけなので、かなり大変なんです。","ENG":"Most of the time we don't get much more than a half-empty case file to begin our investigation, you see.","TWN":"調查用說的很簡單，但拿著事件的檔案夾到處跑可不是件容易的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런 면에서 강소영 경위님은 정말 타고났다고 봐야죠.","JPN":"そういう面では、マエカワ警部補に天賦の才があるとしか思えません。","ENG":"So Lieutenant Kang sure is amazing when it comes to finding leads and whatnot.","TWN":"但在這方面，姜警衛真的是個天才。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"오죽하면 자존심 강한 저희 팀장님도 막히는 수사가 있을 땐 저희 몰래 강소영 경위님을 찾아간다니까요?","JPN":"プライドが高いうちのリーダーも、行き詰った時は私たちに内緒で、マエカワ警部補に会いに行くほどです。","ENG":"Even our team's boss secretly asks her for help when we hit a wall with a case. Of course, he's too proud to admit he ever does that.","TWN":"不然我們組長自尊心那麼強，怎麼會每次在調查遇到瓶頸時，都會偷偷去找姜警衛？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"4기동 실적이 유달리 낮은 건 다름이 아니라, 까다로운 카운터 범죄만 전담하는 독특한 부서라서 그런 거에요.","JPN":"とりわけ第4特別機動捜査隊の実績が低いのは、面倒なカウンター犯罪を担当する特殊な部署だからなんです。","ENG":"SWAT 4 hasn't been getting much credit because they specialize in crimes committed by Counters, which can be quite a complicated thing to deal with.","TWN":"其實第四機動業績差很正常，因為他們這個特殊部門，只負責調查那些棘手的制裁者犯罪。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"지금은 혼자 뿐인 강소영 경위님에게도 등을 믿고 맡길 수 있는 팀원이 생긴다면......","JPN":"今は一人で頑張ってるマエカワ警部補に、背中を預けられるチームメンバーが現れれば……","ENG":"Lieutenant Kang may be all alone now, but if she could ever find a reliable partner on her team...","TWN":"如果單槍匹馬的姜警衛也能有個並肩作戰的隊友……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그때는 4기동도 금방 유배지라는 오명을 벗을 수 있을 거라고 생각해요.","JPN":"第4特別機動捜査隊も、左遷先という汚名を返上できると思います。","ENG":"I'm sure SWAT 4 will no longer be considered a place of exile.","TWN":"我想那時，第四機動就能擺脫流放地這個汙名了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아...... 제가 거기에 지원할 마음은 없냐고요?","JPN":"あ……私ですか？","ENG":"Oh... Am I interested applying for a transfer there at all?","TWN":"啊……你問我想不想去幫忙？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하하 그, 그건 좀...... 부서이동이란 게 그리 간단한 일이 아니라서 좀 고민을 해봐야겠네요.","JPN":"はは、そ、それはちょっと……部署の移動は簡単ではないので、少し考えてみます。","ENG":"Hah hah, I don't know, that's a little... I mean, transfers are easier said than done, so I'll have to give it some more thought.","TWN":"哈哈，那、那有點……部門調動可沒那麼容易，我要稍微考慮一下。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니 제가 바쁜 일이 있어서...... 인터뷰는 여기까지 할게요, 하하......","JPN":"あ、用事があるのを忘れてました……それじゃあ、インタビューはここまでということで、はは……","ENG":"Oh, I just remembered I'm running late for an appointment... I think that's all the time I've got for this interview... hah hah...","TWN":"話說回來，我有件事情要忙……採訪就到此為止吧，哈哈……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 강소영 경위님을 찾으신다고요?","JPN":"あ、マエカワ警部補をお探しですか？","ENG":"Oh, you're looking for Lieutenant Kang?","TWN":"啊，您要找姜素英警衛嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아마 회의실에 가면 만나보실 수 있을 거에요. ","JPN":"たぶん会議室にいらっしゃると思います。 ","ENG":"You can probably find her in the conference room. ","TWN":"去會議室應該就能見到她了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"청장님 지시로 근무 중 차량파손 건에 대한 시말서를 쓰고 계시거든요.","JPN":"署長の指示で、勤務中の車両破損に関する始末書を書いていらっしゃいます。","ENG":"The Commissioner ordered her to write a statement on the vehicle she wrecked while on the clock.","TWN":"局長命令她寫一份值勤車輛損壞的悔過書。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};